require.config({"config": {
        "text":{"Magento_PaymentServicesPaypal/template/payment/apm-method.html":"<!--\n/**\n* ADOBE CONFIDENTIAL\n*\n* Copyright 2026 Adobe\n* All Rights Reserved.\n*\n* NOTICE: All information contained herein is, and remains\n* the property of Adobe and its suppliers, if any. The intellectual\n* and technical concepts contained herein are proprietary to Adobe\n* and its suppliers and are protected by all applicable intellectual\n* property laws, including trade secret and copyright laws.\n* Dissemination of this information or reproduction of this material\n* is strictly forbidden unless prior written permission is obtained\n* from Adobe.\n*/\n-->\n<!-- ko if: (isEligible) -->\n    <div data-bind=\"attr: {class: 'payment-method payment-method-payment_services_paypal_apm payment-method-' + getApmCode()}, css: {'_active': isActive()}, afterRender: hideIdeal\">\n        <div class=\"payment-method-title field choice\">\n            <input type=\"radio\"\n                name=\"payment[method]\"\n                class=\"radio\"\n                data-bind=\"\n                        attr: {'id': getApmCode()},\n                        value: getApmCode(),\n                        click: selectPaymentMethod,\n                        visible: isRadioButtonVisible()\">\n            <label class=\"label\" data-bind=\"attr: {'for': getApmCode()}\">\n                <span class=\"payment-services-paypal-apm-mark\" data-bind=\"afterRender: renderPaymentMark\"></span>\n                <span data-bind=\"text: getTitle()\"></span>\n            </label>\n        </div>\n        <div id=\"checkout-form\" class=\"payment-method-content\">\n            <!-- ko foreach: getRegion('messages') -->\n            <!-- ko template: getTemplate() --><!-- /ko -->\n            <!--/ko-->\n            <div class=\"payment-method-billing-address\">\n                <!-- ko foreach: parentBilling.getRegion(getBillingAddressFormName()) -->\n                <!-- ko template: getTemplate() --><!-- /ko -->\n                <!--/ko-->\n            </div>\n            <div class=\"checkout-agreements-block\">\n                <!-- ko foreach: parentBilling.getRegion('before-place-order') -->\n                <!-- ko template: getTemplate() --><!-- /ko -->\n                <!--/ko-->\n            </div>\n            <div class=\"card-container\" data-bind=\"css: {'payment-services-paypal-apm-disabled': !isPlaceOrderActionAllowed()}\">\n                <div data-bind=\"attr: { id: 'paypal_' + method + '_fields' }\"></div>\n                <div data-bind=\"attr: { id: 'paypal_' + method + '_button' }\"></div>\n            </div>\n        </div>\n    </div>\n<!-- /ko -->\n"}
}});
